mapper.sql:
FROM security_events
WHERE deleted_at IS NULL

    AND (event_type LIKE CONCAT('%', #{keyword}, '%')
    OR reason LIKE CONCAT('%', #{keyword}, '%')
    OR recommendation LIKE CONCAT('%', #{keyword}, '%'))


    AND risk_level = #{riskLevel}


    AND status = #{status}


    AND channel = #{channel}


    AND detected_at >= #{startDate}


    AND detected_at <= #{endDate}

