INSERT INTO security_events (
    user_id, event_type, risk_level, status, channel, detected_at, reason, recommendation, created_at, updated_at, deleted_at
) VALUES (
    #{userId}, #{eventType}, #{riskLevel}, #{status}, #{channel}, #{detectedAt}, #{reason}, #{recommendation}, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, NULL
)
